INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('094454b5-4ffd-4e9a-9cb4-25cd19abcf49', NOW(), 1300, 'Black', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Logitech Lift is a unique vertical ergonomic mouse designed to place the hand in a natural handshake position, reducing wrist strain and promoting better forearm posture. This design is highly recommended for office professionals and those who spend long hours working. It features SilentTouch Technology, which reduces click noise by 90% compared to traditional mice, making it ideal for quiet environments. It connects seamlessly via Bluetooth or the included Logi Bolt receiver, supporting multiple device switching. The precision optical sensor and four customizable buttons focus entirely on productivity and comfort. Though designed for work, its comfortable, contoured shape is perfect for a palm grip. The mouse is powered by a single AA battery, offering exceptional, multi-month battery life.', 4000, 'PALM', 'products/bg90gaj8fgstlifxcyyo', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691904/products/bg90gaj8fgstlifxcyyo.webp', 'Logitech Lift Vertical Ergonomic Mouse', 6, 125, 69.99, true, 190, false, 'OPTICAL', 'logitech-lift-vertical-ergonomic-mouse', 125, true, '7b420bcf-47eb-4492-93ed-44ffa65c7a85') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('0c936aaf-c868-4cf6-84ab-7371b355f306', NOW(), 1680, 'Pale Gray', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Logitech MX Master 3S is the ultimate productivity mouse, designed for coders, designers, and creatives. It features the incredibly precise Darkfield sensor, which tracks flawlessly on virtually any surface, including glass. Its main attraction is the MagSpeed electromagnetic scroll wheel, which can scroll 1,000 lines in one second and automatically switches between line-by-line and free-spin modes. The mouse supports Flow technology, allowing seamless control and file transfer between up to three computers running different operating systems. It uses quiet clicks for minimal disturbance. The advanced, sculpted ergonomic shape is designed for all-day comfort for the right hand, making it the benchmark for professional use.', 8000, 'PALM', 'products/ghzidz0amvahk0r57wfm', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764693249/products/ghzidz0amvahk0r57wfm.webp', 'Logitech MX Master 3S', 5, 125, 99.99, true, 170, false, 'OPTICAL', 'logitech-mx-master-3s', 141, true, '7b420bcf-47eb-4492-93ed-44ffa65c7a85') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('0ff2baf2-0bc1-493f-82e7-01dbc2c3f118', NOW(), 180, 'Black (Perforated)', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The SteelSeries Aerox 5 Wireless is an ultra-lightweight mouse designed for maximum performance, weighing only 74 grams due to its perforated Honeycomb design. Despite the open shell, the mouse is IP53 rated, protecting internal components from dust and water splashes. It uses the TrueMove Air optical sensor with a maximum sensitivity of 18,000 DPI, providing excellent 1-to-1 tracking precision. This model stands out with a large number of programmable buttons, including a unique ''up/down'' switch, ideal for assigning key shortcuts in MOBA and MMO games. The advanced Quantum 2.0 Wireless technology allows switching between a fast 2.4 GHz connection and Bluetooth, offering a record battery life of up to 180 hours. The RGB lighting is dynamic and fully customizable. It''s the ideal choice for players who need the lightness of an FPS mouse but also expect versatility due to the extra buttons.', 18000, 'FINGERTIP', 'products/mbadcejwx39vi1zrpx3e', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690343/products/mbadcejwx39vi1zrpx3e.webp', 'SteelSeries Aerox 5 Wireless', 9, 1000, 109.99, true, 150, true, 'OPTICAL', 'steelseries-aerox-5-wireless', 74, true, '979c998a-1ffd-4347-8f1f-56480df0951e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('1fe05a6a-3d37-4266-91a5-bf3d2001781a', NOW(), NULL, 'Black', 'USB', 'The Razer Viper 8K Hz is a wired esports mouse built for uncompromising speed and minimal latency, featuring true 8000 Hz HyperPolling Technology. This means the mouse sends data to the PC 8000 times per second, resulting in virtually zero input delay, which is critical for top-tier competitive play. It uses the precise Focus+ Optical Sensor and Razer Optical Mouse Switches Gen-2 for actuation speed that is 3x faster than traditional mechanical switches. The mouse maintains a lightweight, ambidextrous design at 71 grams, ensuring quick, effortless swipes. Its flexible Razer Speedflex Cable minimizes drag. The Viper 8K is specifically aimed at serious e-sports athletes who demand the absolute lowest latency from a wired connection.', 20000, 'CLAW', 'products/d2slosp1gi0zus9ydasi', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691970/products/d2slosp1gi0zus9ydasi.webp', 'Razer Viper 8K', 8, 8000, 79.99, true, 85, true, 'OPTICAL', 'razer-viper-8k', 71, false, 'a61c0eb7-178e-4b83-a40d-a33b838c5e29') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('24b1426b-fe57-4f8a-820a-14e95f81d56e', NOW(), 180, 'Black (Perforated)', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The SteelSeries Aerox 9 Wireless is a breakthrough mouse for MMO and MOBA players, combining the necessity of multiple programmable buttons with an ultra-lightweight, perforated design (weighing only 89 grams). It features a 12-button side panel specifically configured for quick access to spells and commands. Equipped with the TrueMove Air sensor and Quantum 2.0 Wireless technology, it delivers precise 18,000 DPI tracking and ultra-low latency, while providing up to 180 hours of battery life. Like other Aerox models, it has an IP54 rating for protection against dust and spills. This mouse eliminates the common trade-off between the heavy weight of traditional MMO mice and the need for speed and agility.', 18000, 'PALM', 'products/divs8x5eno6gzaie9i27', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764693170/products/divs8x5eno6gzaie9i27.webp', 'SteelSeries Aerox 9 Wireless', 18, 1000, 149.99, true, 90, true, 'OPTICAL', 'steelseries-aerox-9-wireless', 89, true, '979c998a-1ffd-4347-8f1f-56480df0951e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('4eaf2a4d-a71f-4d15-ba48-e116e39df7e9', NOW(), 120, 'White', 'WIRELESS_2_4GHZ', 'The Logitech G502 X PLUS is the latest evolution of the world''s most popular gaming mouse, blending the iconic, feature-rich design with new lightspeed technologies. It features LIGHTFORCE hybrid optical-mechanical switches, offering the speed of optical actuation with the crisp, tactile feel of a mechanical switch. This model includes 13 fully programmable buttons and the legendary dual-mode scroll wheel (hyper-fast or ratcheted). The LIGHTSYNC RGB has an 8-LED lighting array, providing dynamic, fully customizable effects. With the HERO 25K sensor and LIGHTSPEED wireless technology, it delivers sub-millisecond precision and reliable performance. Although heavier than ultra-light mice, its weight and comfort are preferred by players requiring maximum button accessibility and a full-palm grip.', 25600, 'PALM', 'products/plnbbpjz1qdtdcqdqpgj', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691135/products/plnbbpjz1qdtdcqdqpgj.webp', 'Logitech G502 X PLUS', 13, 1000, 159.99, true, 115, true, 'OPTICAL', 'logitech-g502-x-plus', 89, true, '7b420bcf-47eb-4492-93ed-44ffa65c7a85') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('5646670b-eb7f-490f-838d-fbf099dbf53a', NOW(), 80, 'Black', 'WIRELESS_2_4GHZ', 'The Razer Viper V2 Pro is a highly specialized, ultra-lightweight esports mouse designed for peak competitive performance. Weighing only 58 grams, it is one of the lightest wireless mice available, ensuring minimum fatigue and maximum speed. It features the cutting-edge Focus Pro 30K Optical Sensor and Razer Optical Mouse Switches Gen-3, providing incredibly fast actuation with zero debounce issues. The mouse supports Razer HyperPolling Wireless Technology (up to 4000 Hz with a separate dongle, though standard is 1000 Hz), delivering true competitive responsiveness. Its minimalist, symmetrical design and lack of RGB lighting prioritize function and weight reduction. This model is perfect for professional players and serious enthusiasts who require the absolute fastest and lightest gear.', 30000, 'CLAW', 'products/araz4tdgqjrjmf1fingn', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691071/products/araz4tdgqjrjmf1fingn.webp', 'Razer Viper V2 Pro', 5, 1000, 149.99, true, 100, false, 'OPTICAL', 'razer-viper-v2-pro', 58, true, 'a61c0eb7-178e-4b83-a40d-a33b838c5e29') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('5d11ac5a-398f-465f-9801-377415eed14a', NOW(), 540, 'Iron Gray', 'WIRELESS_2_4GHZ', 'Designed for maximum precision in professional environments, the Lenovo Professional Wireless Laser Mouse is an indispensable tool for business users. It utilizes a highly accurate Laser sensor, making it reliable on a wide variety of difficult surfaces, including glossy desks where optical sensors often fail. The ergonomic contour is crafted for extended, all-day comfort. It features a simplified, five-button layout, with a dedicated side button for quick access to Windows functions. The connection is handled via a reliable 2.4 GHz USB receiver, ensuring a stable, interference-free link. Built without any gaming features like high polling rates or RGB, this mouse focuses purely on durability, precision, and efficiency, offering exceptional battery longevity perfect for the corporate setting.', 1600, 'PALM', 'products/yy6dcijgrv7dajpnbicy', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691658/products/yy6dcijgrv7dajpnbicy.webp', 'Lenovo Professional Wireless', 5, 125, 29.99, false, 250, false, 'LASER', 'lenovo-professional-wireless', 90, true, '3949c8b9-4fa5-4660-88c9-4aa46e26557e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('60561781-a3e1-4168-93b9-2a772a55aa78', NOW(), 71, 'Matte White', 'WIRELESS_2_4GHZ', 'The Glorious Model D Wireless is an ergonomically contoured, ultra-lightweight wireless mouse that combines the comfort of a PALM grip with an incredibly low weight of 69 grams. The refined Honeycomb shell design ensures maximum palm ventilation while maintaining high durability. The mouse is equipped with the BAMF optical sensor (based on PAW3370), which offers sensitivity up to 19,000 DPI, providing exceptional precision and lag-free tracking. The use of 2.4 GHz wireless connectivity minimizes latency to just 1ms. The Ascended Cord RGB lighting adds style, and the durable G-Skates PTFE feet ensure extremely smooth movement across any mousepad. The Model D Wireless is the perfect solution for gamers who value speed, comfort, and the freedom of a wireless connection without sacrificing full gaming functionality.', 19000, 'PALM', 'products/xxirgkccb3otvsxo1zht', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690525/products/xxirgkccb3otvsxo1zht.webp', 'Glorious Model D Wireless', 5, 1000, 99.99, true, 110, true, 'OPTICAL', 'glorious-model-d-wireless', 69, true, '55939404-8631-4aa2-ad99-7b0f911951f8') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('6f075039-6773-4682-9640-a47e6b6a6e51', NOW(), 70, 'Black', 'WIRELESS_2_4GHZ', 'The Logitech G Pro X Superlight is the pinnacle of esports engineering, designed in collaboration with the world''s top professionals. The key to its dominance is its ultra-low weight of just 63 grams, ensuring unparalleled speed and precision of movement, which is crucial in dynamic FPS games. Despite the lack of RGB lighting, the mouse focuses on pure performance, featuring the advanced HERO 25K sensor with a resolution of 25,600 DPI. It provides sub-micron accuracy tracking without any smoothing or filtering. The LIGHTSPEED wireless technology guarantees a stable and fast connection with a 1000 Hz polling rate, eliminating the latency typical of older technologies. The battery lasts up to 70 hours of continuous gaming. This is the ideal choice for players seeking maximum performance and reliability in competitive play.', 25600, 'CLAW', 'products/cheqssue0q6jbo6qdjvj', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690635/products/cheqssue0q6jbo6qdjvj.webp', 'Logitech G Pro X Superlight', 5, 1000, 149.99, true, 120, false, 'OPTICAL', 'logitech-g-pro-x-superlight', 63, true, '7b420bcf-47eb-4492-93ed-44ffa65c7a85') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('728406c3-299d-4766-9500-e977e609fd61', NOW(), NULL, 'Black', 'USB', 'The ZOWIE S2-C is a compact, symmetrical wired mouse specifically optimized for Claw and Fingertip grips in competitive FPS gaming. It features a lower profile and shorter overall length than ZOWIE''s EC-series, making it easier to maneuver with the fingers. The mouse is equipped with the reliable 3360 optical sensor and boasts a lightweight design at 69 grams. It uses a flexible paracord-like cable (ZOWIE''s Paracord) to minimize drag, offering a near-wireless feel. Crucially, like all C-series ZOWIE mice, it is entirely driverless (no software needed), ensuring consistent, tournament-ready performance. All adjustments (DPI, polling rate) are made via buttons on the base. The lack of RGB and unnecessary features highlights its pure focus on competitive performance and reliability.', 3200, 'FINGERTIP', 'products/iuyjdv7nwakt5sncycxt', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764693348/products/iuyjdv7nwakt5sncycxt.webp', 'Zowie S2-C', 5, 1000, 69.99, false, 110, false, 'OPTICAL', 'zowie-s2-c', 69, false, 'd63ace68-f8f4-4d75-ba5c-52e447e2ae03') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('7758e5a6-6781-4b1b-a10e-c6592e7a6ce6', NOW(), NULL, 'Black', 'USB', 'The Corsair M65 RGB ULTRA is an advanced FPS gaming mouse, recognized for its durable metal frame and specialized ergonomic design centered around a dedicated ''Sniper Button''. It utilizes the ultra-fast Corsair MARKSMAN 26,000 DPI optical sensor and features AXON Hyper-Processing Technology, enabling a native polling rate of up to 8,000 Hz (8x faster than standard gaming mice), providing near-instantaneous response times. The mouse also includes a fully customizable weight system, allowing users to fine-tune the center of gravity and weight from 97g up to 115g. Its Quickstrike buttons use optical switches for lightning-fast clicks. This mouse is built for competitive players who demand hyper-fast signaling and an extremely sturdy, adjustable body.', 26000, 'CLAW', 'products/lfundvqc4qhy5eypqscm', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691201/products/lfundvqc4qhy5eypqscm.webp', 'Corsair M65 RGB ULTRA', 8, 8000, 79.99, true, 94, true, 'OPTICAL', 'corsair-m65-rgb-ultra', 97, false, 'b41e85cb-0e0c-4775-89af-e12f3e28a116') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('aa322ead-47f8-4157-92bf-648a891e2436', NOW(), 90, 'Black', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Razer Basilisk V3 Pro is an uncompromising, ergonomic gaming mouse. Equipped with the Razer Focus Pro 30K Optical Sensor, it achieves a resolution of up to 30,000 DPI, guaranteeing unparalleled precision and tracking on almost any surface. The mouse utilizes Razer Optical Switches Gen-3, characterized by instantaneous response time and a lifespan of up to 90 million clicks. The true distinguishing feature is the advanced HyperScroll Tilt Wheel, which automatically switches between tactile and super-fast free-spin scrolling modes. This model has 11 programmable buttons, including the characteristic ''sniper'' button, which instantly lowers the DPI. Full, customizable Chroma RGB lighting covers 13 zones, creating an immersive visual effect. Thanks to HyperSpeed Wireless technology, the connection is stable and latency is minimal, making it the perfect tool for both intense gaming and professional work.', 30000, 'PALM', 'products/pyy1lmr2bsik7siflp5n', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690235/products/pyy1lmr2bsik7siflp5n.webp', 'Razer Basilisk V3 Pro', 11, 1000, 159.99, true, 90, true, 'OPTICAL', 'razer-basilisk-v3-pro', 112, true, 'a61c0eb7-178e-4b83-a40d-a33b838c5e29') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('aadc06c1-8296-4052-9ec2-5287aa715ee0', NOW(), 70, 'Black', 'WIRELESS_2_4GHZ', 'The ZOWIE EC2-CW is the epitome of competitive simplicity, favored by FPS professionals for its flawless performance and ergonomic shape. Designed specifically for the right hand, its shape ensures maximum comfort during long training sessions. The EC2-CW uses a high-performance 3370 optical sensor that is focused on consistent, raw tracking rather than high DPI numbers. Critically, ZOWIE mice are designed to be entirely driverless, allowing gamers to plug-and-play and adjust DPI and Polling Rate directly on the mouse base without software interference, making them tournament-ready instantly. The mouse is lightweight and features a reliable low-latency wireless connection, providing the freedom of wireless without sacrificing the responsiveness of a wired mouse. It features no RGB lighting and minimal, essential buttons, aligning with the brand''s philosophy of pure competitive focus.', 3200, 'PALM', 'products/tbnkqdffkeaztwpqcxav', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690803/products/tbnkqdffkeaztwpqcxav.webp', 'Zowie EC2-CW', 5, 1000, 149.00, false, 75, false, 'OPTICAL', 'zowie-ec2-cw', 77, true, 'd63ace68-f8f4-4d75-ba5c-52e447e2ae03') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('bec4aba4-2830-42f9-97a6-b1335bb8e8e4', NOW(), 71, 'Black Matte', 'WIRELESS_2_4GHZ', 'The Glorious Model O Wireless is an ambidextrous, ultra-lightweight gaming mouse renowned for its symmetrical design and perforated shell, weighing just 69 grams. It provides the ultimate freedom of movement thanks to the proprietary BAMF wireless sensor which delivers a maximum DPI of 19,000 and is optimized for low power consumption. This mouse offers a virtually lag-free wireless experience using 2.4 GHz connectivity. Its flexible, braided charging cable (Ascended Cord) allows for smooth wired play if the battery runs low. The Model O is fitted with super-smooth G-Skates PTFE feet for effortless gliding. With full RGB lighting around the sides and scroll wheel, it''s a perfect blend of high performance, customizable aesthetics, and ergonomic comfort for both left and right-handed users.', 19000, 'CLAW', 'products/bq0cf3glb3lv7xkqugz9', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691585/products/bq0cf3glb3lv7xkqugz9.webp', 'Glorious Model O Wireless', 6, 1000, 89.99, true, 140, true, 'OPTICAL', 'glorious-model-o-wireless', 69, true, '55939404-8631-4aa2-ad99-7b0f911951f8') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('c053a903-5ce0-4dc1-8343-612b9babcc66', NOW(), NULL, 'Black', 'USB', 'The SteelSeries Aerox 3 is a streamlined, ultra-lightweight wired gaming mouse, weighing in at an incredibly low 59 grams thanks to its perforated honeycomb shell. Built for speed and maximum responsiveness, it features the TrueMove Core optical sensor which offers true 1-to-1 tracking and excellent accuracy up to 8,500 DPI. The mouse is designed for optimal performance with minimal hand strain, perfect for rapid movements in competitive FPS games. Despite its open design, it is highly durable and features an IP54 rating for water and dust resistance. It uses a super mesh cable to reduce drag and ensure smooth, unrestricted swipes. The brilliant PrismSync lighting system provides three zones of vibrant, customizable RGB illumination, making it a stylish yet highly functional choice for budget-conscious performance seekers.', 8500, 'FINGERTIP', 'products/kcwikfkrtrv34ynjvvlz', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764691509/products/kcwikfkrtrv34ynjvvlz.webp', 'SteelSeries Aerox 3', 6, 1000, 49.99, true, 180, true, 'OPTICAL', 'steelseries-aerox-3', 58, false, '979c998a-1ffd-4347-8f1f-56480df0951e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('e5b543d6-9f5b-416b-82b9-727270cfeb02', NOW(), 70, 'Storm Grey', 'WIRELESS_2_4GHZ', 'The Lenovo Legion M600 is a versatile, wireless gaming mouse designed to offer seamless, lag-free performance for both competitive gaming and daily use. It provides triple connection options: sub-1ms 2.4 GHz wireless, Bluetooth, and wired USB-C, ensuring maximum flexibility. Equipped with an accurate PixArt 3335 optical sensor, it delivers up to 16,000 DPI. Its key feature is the extended battery life, providing up to 200 hours on a single charge, with quick charging capability—a 10-minute charge gives 10 hours of play. The ambidextrous design is comfortable for various grip styles, and the customizable Legion signature RGB lighting adds a sharp aesthetic. This mouse balances high-speed performance and professional endurance, making it a reliable all-rounder.', 19000, 'CLAW', 'products/wps4up1adllcbi0tg5am', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1762948752/products/wps4up1adllcbi0tg5am.jpg', 'Lenovo Legion M600 Wireless', 6, NULL, 59.99, true, 85, true, 'OPTICAL', 'lenovo-legion-m600-wireless', 74, true, '3949c8b9-4fa5-4660-88c9-4aa46e26557e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('ffe5689b-fd81-41b5-b005-5c64cce51f2f', NOW(), 50, 'Black', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Corsair Dark Core RGB Pro SE is a high-performance wireless mouse created for the most demanding gamers who prioritize comfort and complete control. Its ergonomic shape, featuring interchangeable side grips, perfectly adapts to the hand. It stands out with ultra-fast SLIPSTREAM WIRELESS technology and an incredibly high polling rate of 2000 Hz, providing twice the communication speed of standard gaming mice. The heart of the mouse is the precise Corsair Marksman 18,000 DPI optical sensor. The key feature of the SE model is the built-in support for Qi wireless charging, allowing for easy and convenient battery top-ups on compatible mousepads (e.g., Corsair MM1000). Nine zones of dynamic RGB lighting, controlled by iCUE software, allow for full synchronization with other Corsair hardware.', 18000, 'PALM', 'products/zvnhmfi43z4xqmcmlcci', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690511/products/zvnhmfi43z4xqmcmlcci.png', 'Corsair Dark Core RGB SE', 8, 2000, 119.99, true, 80, true, 'OPTICAL', 'corsair-dark-core-rgb-se', 128, true, 'b41e85cb-0e0c-4775-89af-e12f3e28a116') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('f4d87711-f516-4ca4-8643-a1493cd119aa', NOW(), 110, 'Black', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Corsair KATAR ELITE Wireless is a compact, lightweight mouse designed for fast-paced claw and fingertip grip players. Weighing just 73 grams, it offers superb agility and control. It utilizes the powerful Corsair MARKSMAN 26,000 DPI optical sensor and ultra-fast SLIPSTREAM WIRELESS technology. This mouse is unique for its use of AXON Hyper-Processing Technology to achieve a blazing fast 2,000 Hz polling rate wirelessly, providing a competitive edge with reduced latency. The KATAR ELITE is equipped with Corsair''s durable, optical switches. Its small footprint and symmetrical shape make it highly suitable for travel and players with smaller hands who prefer compact, responsive gear. It includes simple RGB lighting for subtle aesthetics.', 26000, 'FINGERTIP', 'products/hjd22thmy9wqanddjaz8', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764692029/products/hjd22thmy9wqanddjaz8.webp', 'Corsair KATAR ELITE Wireless', 6, 2000, 79.99, true, 128, true, 'OPTICAL', 'corsair-katar-elite-wireless', 73, true, 'b41e85cb-0e0c-4775-89af-e12f3e28a116') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('25786b20-747e-4a4e-b4e1-a75dc549ff00', NOW(), 360, 'Storm Grey', 'WIRELESS_2_4GHZ_BLUETOOTH', 'The Lenovo Go Wireless Multi-Device Mouse is designed for the modern professional who requires flexibility and precision across multiple devices. Its distinctive USB-C charging port and ability to seamlessly pair with up to three devices via Bluetooth and 2.4 GHz make it highly versatile. The mouse features a premium blue optical sensor that works reliably on virtually any surface, including glass. While focusing on productivity, it maintains a comfortable, contoured shape suitable for extended use. The central utility button allows for on-the-fly DPI adjustment and quick connection swapping. Its minimal aesthetic and muted color scheme are ideal for corporate or home office environments. The absence of complex macros and RGB focuses the design entirely on essential, multi-platform functionality and long battery life.', 2400, 'PALM', 'products/kj9vdnthtsefv3j396zq', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764690886/products/kj9vdnthtsefv3j396zq.webp', 'Lenovo Go Wireless Multi-Device Mouse', 5, 125, 59.99, false, 199, false, 'OPTICAL', 'lenovo-go-wireless-multi-device-mouse', 71, true, '3949c8b9-4fa5-4660-88c9-4aa46e26557e') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, added_at, battery_life, color, connection_type, description, dpi, grip_type, image_public_id, image_url, name, number_of_buttons, polling_rate, price, programmable_buttons, quantity, rgb_lighting, sensor_type, slug, weight, wireless, brand_id) VALUES ('12303c3d-bf23-48da-95ea-2c4d03b7b9ab', NOW(), NULL, 'Black', 'USB', 'The Logitech G502 Hero is one of the most recognized and best-selling wired gaming mice globally, celebrated for its unique ergonomic design and abundance of features. It utilizes the proprietary HERO 25K sensor, delivering exceptional precision up to 25,600 DPI with zero smoothing, filtering, or acceleration. The mouse features 11 fully programmable buttons and the famous dual-mode, hyper-fast scroll wheel, which toggles between ratchet and free-spinning modes. A standout feature is the Tuneable Weight System, allowing users to adjust the weight and balance (up to 5x 3.6g weights) to perfectly match their play style. Its aggressive, right-hand-focused ergonomic shape supports a solid palm grip. The integrated LIGHTSYNC RGB allows for dynamic lighting effects synchronized with gameplay. This mouse is the benchmark for high-DPI, customizable wired performance.', 16000, 'PALM', 'products/jb3z91ebzujmwgytmsvp', 'https://res.cloudinary.com/drtgydqdw/image/upload/v1764083713/products/jb3z91ebzujmwgytmsvp.jpg', 'Logitech G502 Hero', 11, NULL, 99.99, false, 49, true, 'OPTICAL', 'logitech-g502-hero', 121, false, '7b420bcf-47eb-4492-93ed-44ffa65c7a85') ON CONFLICT (id) DO NOTHING;
